var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아, 이건 목장갑이에요. 회사 앞 공원에 다녀 오려고요.","JPN":"あ、これは軍手です。会社前の公園に行ってこようと思って。","ENG":"Oh, these are gardening gloves. I'm going to swing by the park in front of the office.","TWN":"啊，這是棉手套。我想去公司前面的公園。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"미리 먹을 수 있는 풀을 모아 두면 이면세계에서 조난됐을 때 분명 유용할 거예요!","JPN":"食用の草を事前に集めておけば、カウンターサイドで遭難した時にきっと役立つと思いますよ！","ENG":"I'm sure foraging some edible grass will come in handy for when we get stranded on the Counterside!","TWN":"如果提前收集好可食用的草，在異界碰到困難的時候肯定能派上用場的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"앗?! 가, 갑자기 왜 우세요? 제가 뭔가 말을 잘못했나요?","JPN":"あっ！？な、何で急に泣き出すんですか？私何かまずいことでも言いましたか？","ENG":"Huh?! W-why are you crying? Was it something I said?","TWN":"啊？！為，為什麼突然掉眼淚了啊？是我說錯什麼了嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"눈물 요정아, 달아나라! 뚝!","JPN":"涙の妖精よ、飛んでけ！","ENG":"Go away, tear fairy! Shoo!","TWN":"眼淚啊，快飛的遠遠的！停！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"헤헤. 이제 괜찮을 거예요. 옆집 아주머니가 가르쳐 줬던 주문이거든요.","JPN":"へへ、これで大丈夫ですよ。お隣のおばあさんに教えてもらったおまじないです。","ENG":"Heh. You'll be okay now. The lady next door taught me that spell.","TWN":"嘿嘿。現在好了，這是鄰居大嬸教我的咒語。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"엄마랑 아빠가 저녁 내내 집에 안 들어와서 울고 있으면, 이 주문을 외워 주셨어요.","JPN":"お父さんとお母さんが深夜まで帰ってこなくて泣いてると、このおまじないをかけてくれたんです。","ENG":"She'd say it for me whenever I sat home and cried because my parents wouldn't come home till late.","TWN":"每當爸爸媽媽晚上不會回家的時候，我就會念一念這個咒語。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"사실 여기 오는 동안 더 신세지긴 싫다고 말씀드려야 하나 고민했어요.","JPN":"実はここに来るまでに、これ以上迷惑をかけたくないと言うべきか悩みました。","ENG":"Honestly, I wondered if I should tell you; I'd hate to be a burden on you much longer.","TWN":"其實來這裡的這段時間，我一直在苦惱不想再麻煩您了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"저는 언니처럼 강하지도 않고, 대표님처럼 일을 잘하지도 못하는 사고뭉치니까요.","JPN":"私は姉のように強くもないし、社長みたいに仕事ができる人でもない、ただの問題児ですから。","ENG":"I'm not as strong as Rita, or good at my work like the Boss. I'm just a troublemaker.","TWN":"因爲我不像姐姐那麼堅強或像老闆一樣總是能把工作做好的那種闖禍精。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"엄마랑 아빠도 너 같은 건 괜히 태어났다고 했거든요. 카운터가 되니 달라졌지만요.","JPN":"両親は私なんか生まれてこなければよかったと言ってました。カウンターになってからは態度が変わりましたけど。","ENG":"Even my parents told me someone useless like me should have never been born. Of course, that all changed when I became a Counter.","TWN":"我的爸爸媽媽也常說我沒用。雖然成了制裁者之後，變得有些不同了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"네. 제 워치는 다른 애들처럼 엄마 아빠한테 칭찬 받고 싶다고 빌었을 때 나타났어요.","JPN":"はい。私のウォッチは、他の子たちのようにお父さんとお母さんに褒められたいと願った時に現れました。","ENG":"That's right. I got my Watch when I wished my parents would say nice things about me like other kids' parents.","TWN":"是的，我的能量環像其他孩子一樣，想要得到爸媽的稱讚時會出現。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"카운터가 된 뒤에 엄마 아빠가 칭찬해 줘서 소원이 이루어졌다고 생각했는데......","JPN":"カウンターになってからは両親に褒められて、願いが叶ったと思ったんですが……","ENG":"I thought my wish came true, because my parents finally said nice things to me after I became a Counter…","TWN":"成為制裁者後，爸爸媽媽特別表揚了我，我以為我已經如償所願了……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니랑, 그리고 대표님이랑 같이 지내면서 알게 됐어요.","JPN":"姉と、そして社長と一緒に過ごしているうちに気づいたんです。","ENG":"But I realized the truth once I began working with Rita and the Boss.","TWN":"但是跟姐姐和老闆一起生活之後，我知道了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"저는 그저 다 같이 행복하게 살고 싶었던 거예요. 가난하더라도, 힘들더라도.","JPN":"たとえどんなに貧しくて苦しくても、私はただみんなと一緒に、幸せに暮らしたかっただけなんです。","ENG":"All I wanted was to live happily with everyone else around me. No matter how poor we were or how difficult things got.","TWN":"我只是想和大家一起幸福地生活。貧窮也好，辛苦也罷。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"저 혼자만 아니라, 도움이 필요한 다른 분들도 모두요.","JPN":"私一人だけじゃなくて、助けが必要なみんなで。","ENG":"And not just me either. Anyone else who needed help.","TWN":"不只是我一個人，其他需要幫助的人也是。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그래서 결심했어요! 사장님을 제일 먼저 도와드리자고!","JPN":"だから決心しました！まずは社長を手伝おうと！","ENG":"That's why I made this decision! I decided to help you first!","TWN":"所以我下定決心了！要最先幫老闆！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"왜냐면, 사장님은 침식체들한테서 사람들을 지키는 훌륭한 일을 하는 분이잖아요?","JPN":"なぜなら、社長は侵食体から人を守る立派な仕事をされてる方ですから。","ENG":"Why? Because you're a very nice person who protects people from C.O.s!","TWN":"因為老闆在做保護人類免受侵蝕體傷害的好事！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그러니까 대시가 필요할 때는 언제든 불러 주세요! 무슨 문제든 쓱싹 해치워 드릴게요!","JPN":"だから、私が必要な時はいつでも呼んでください！どんな問題もすぐ解決してあげます！","ENG":"So let me know whenever you need me! I'll help you with anything you need in a blink!","TWN":"所以啊，如果需要黛西，請隨時叫我！不管是什麼問題，我都會幫您解決的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};